def create_saml_response(username, sp_entity_id, acs_url, in_response_to=None):
    user_attrs = USERS[username]['attributes']
    
    response_id = f"_response_{uuid.uuid4().hex}"
    assertion_id = f"_assertion_{uuid.uuid4().hex}"
    issue_instant = datetime.utcnow().strftime('%Y-%m-%dT%H:%M:%SZ')
    not_before = datetime.utcnow().strftime('%Y-%m-%dT%H:%M:%SZ')
    not_on_or_after = (datetime.utcnow() + timedelta(minutes=5)).strftime('%Y-%m-%dT%H:%M:%SZ')
    
    saml_response = f'''<samlp:Response xmlns:samlp="urn:oasis:names:tc:SAML:2.0:protocol"
                        xmlns:saml="urn:oasis:names:tc:SAML:2.0:assertion"
                        ID="{response_id}"
                        Version="2.0"
                        IssueInstant="{issue_instant}"
                        Destination="{acs_url}"
                        {f'InResponseTo="{in_response_to}"' if in_response_to else ''}>
        <saml:Issuer>http://idp.example.com</saml:Issuer>
        <samlp:Status>
            <samlp:StatusCode Value="urn:oasis:names:tc:SAML:2.0:status:Success"/>
        </samlp:Status>
        <saml:Assertion xmlns:saml="urn:oasis:names:tc:SAML:2.0:assertion"
                        ID="{assertion_id}"
                        Version="2.0"
                        IssueInstant="{issue_instant}">
            <saml:Issuer>http://idp.example.com</saml:Issuer>
            <saml:Subject>
                <saml:NameID Format="urn:oasis:names:tc:SAML:1.1:nameid-format:emailAddress">{username}</saml:NameID>
                <saml:SubjectConfirmation Method="urn:oasis:names:tc:SAML:2.0:cm:bearer">
                    <saml:SubjectConfirmationData NotOnOrAfter="{not_on_or_after}"
                                                   Recipient="{acs_url}"
                                                   {f'InResponseTo="{in_response_to}"' if in_response_to else ''}/>
                </saml:SubjectConfirmation>
            </saml:Subject>
            <saml:Conditions NotBefore="{not_before}" NotOnOrAfter="{not_on_or_after}">
                <saml:AudienceRestriction>
                    <saml:Audience>{sp_entity_id}</saml:Audience>
                </saml:AudienceRestriction>
            </saml:Conditions>
            <saml:AuthnStatement AuthnInstant="{issue_instant}" SessionIndex="{assertion_id}">
                <saml:AuthnContext>
                    <saml:AuthnContextClassRef>urn:oasis:names:tc:SAML:2.0:ac:classes:PasswordProtectedTransport</saml:AuthnContextClassRef>
                </saml:AuthnContext>
            </saml:AuthnStatement>
            <saml:AttributeStatement>'''
    
    for attr_name, attr_value in user_attrs.items():
        saml_response += f'''
                <saml:Attribute Name="{attr_name}">
                    <saml:AttributeValue xmlns:xs="http://www.w3.org/2001/XMLSchema"
                                         xmlns:xsi="http://www.w3.org/2001/XMLSchema-instance"
                                         xsi:type="xs:string">{attr_value}</saml:AttributeValue>
                </saml:Attribute>'''
    
    saml_response += '''
            </saml:AttributeStatement>
        </saml:Assertion>
    </samlp:Response>'''
    
    root = etree.fromstring(saml_response.encode('utf-8'))
    
    assertion = root.find('.//{urn:oasis:names:tc:SAML:2.0:assertion}Assertion')
    
    signer = XMLSigner(
        method=signxml.methods.enveloped,
        signature_algorithm='rsa-sha256',
        digest_algorithm='sha256'
    )
    
    signed_assertion = signer.sign(
        assertion,
        key=IDP_PRIVATE_KEY,
        cert=IDP_CERTIFICATE
    )
    
    parent = assertion.getparent()
    parent.replace(assertion, signed_assertion)
    
    signed_response = etree.tostring(root, encoding='unicode')
    
    encoded_response = base64.b64encode(signed_response.encode('utf-8')).decode('utf-8')
    
    return encoded_response

