@app.route('/sso', methods=['GET', 'POST'])
def sso():
    saml_request = request.args.get('SAMLRequest') or request.form.get('SAMLRequest')
    relay_state = request.args.get('RelayState') or request.form.get('RelayState')
    
    if request.method == 'POST':
        username = request.form.get('username')
        password = request.form.get('password')
        
        if username in USERS and USERS[username]['password'] == password:
            if saml_request:
                decoded_request = base64.b64decode(saml_request)
                request_xml = etree.fromstring(decoded_request)
                
                acs_url = request_xml.get('AssertionConsumerServiceURL')
                sp_entity_id = request_xml.find('.//{urn:oasis:names:tc:SAML:2.0:assertion}Issuer').text
                request_id = request_xml.get('ID')
            else:
                sp_entity_id = SERVICE_PROVIDERS['sp1']['entity_id']
                acs_url = SERVICE_PROVIDERS['sp1']['acs_url']
                request_id = None
            
            saml_response = create_saml_response(username, sp_entity_id, acs_url, request_id)
            
            return render_template_string(SAML_POST_FORM, 
                                         acs_url=acs_url, 
                                         saml_response=saml_response,
                                         relay_state=relay_state)
        else:
            return render_template_string(LOGIN_FORM, 
                                         error='Invalid credentials',
                                         saml_request=saml_request,
                                         relay_state=relay_state)
    
    return render_template_string(LOGIN_FORM, 
                                 saml_request=saml_request,
                                 relay_state=relay_state)

